onClick:
{{
(() => {

    // ==========================
    // VALIDAR TIPOS DE RETENCIÓN
    // ==========================

    if (
        Number((inpRetencionItbisAV.text || "0").replace(/,/g,"")) > 0 &&
        !selTipoRetITBIS_AV.selectedOptionValue
    ) {
        showAlert("Debe seleccionar el tipo de retención de ITBIS.", "warning");
        return;
    }

    if (
        Number((inpRetencionDGIIAV.text || "0").replace(/,/g,"")) > 0 &&
        !selTipoRetDGII_AV.selectedOptionValue
    ) {
        showAlert("Debe seleccionar el tipo de retención de DGII.", "warning");
        return;
    }

    if (
        Number((inpRetencionGarantiaAV.text || "0").replace(/,/g,"")) > 0 &&
        !selTipoRetGarantiaAV.selectedOptionValue
    ) {
        showAlert("Debe seleccionar el tipo de retención de Garantía.", "warning");
        return;
    }

    if (
        Number((inpRetencionTSS_AV.text || "0").replace(/,/g,"")) > 0 &&
        !selTipoRetTSS_AV.selectedOptionValue
    ) {
        showAlert("Debe seleccionar el tipo de retención de TSS.", "warning");
        return;
    }

    // ==========================
    // MODIFICAR
    // ==========================

    if (appsmith.store.modoAV === "MODIFICAR") {

        qryAVModificar.run()

        .then(() => {

            showAlert(
                "Avance modificado correctamente.",
                "success"
            );

            return JS_AV.nuevo();

        })

        .catch((e) => {

            showAlert(
                e.message,
                "error"
            );

        });

        return;

    }

    // ==========================
    // CREAR
    // ==========================

    qryAVGuardar.run()

    .then(() => {

        return storeValue(
            "idAVImpresion",
            qryAVGuardar.data[0].id_avance
        );

    })

    .then(() => {

        return storeValue(
            "ultimoAVCreado",
            qryAVGuardar.data[0].numero_avance
        );

    })

    .then(() => {

        showAlert(
            "Avance creado correctamente.",
            "success"
        );

        return JS_AV.nuevo();

    })

    .catch((e) => {

        showAlert(
            e.message,
            "error"
        );

    });

})();
}}
